class Solution:
    def rearrangeCharacters(self, s: str, target: str) -> int:
        s_count = {}
        target_count = {}

        for char in s:
            if char in s_count:
                s_count[char] += 1
            else:
                s_count[char] = 1

        for char in target:
            if char in target_count:
                target_count[char] += 1
            else:
                target_count[char] = 1

        result = float('inf')
        for char, count in target_count.items():
            if char not in s_count:
                return 0
            result = min(result, s_count[char] // count)

        return result
```
